package router

import (
    "fmt"
    "k8s.io/apimachinery/pkg/api/errors"
    "k8s.io/apimachinery/pkg/runtime/schema"
)

type SessionNotFoundError struct {
    SessionID string
}

func NewSessionNotFoundError(sessionID string) *SessionNotFoundError {
    return &SessionNotFoundError{SessionID: sessionID}
}

func (e *SessionNotFoundError) Error() string {
    return fmt.Sprintf("session %s not found", e.SessionID)
}

func (e *SessionNotFoundError) StatusError() *errors.StatusError {
    return errors.NewNotFound(schema.GroupResource{Group: "agentcube.volcano.sh", Resource: "sessions"}, e.SessionID)
}

type SandboxTemplateNotFoundError struct {
    Namespace string
    Name      string
    Kind      string
}

func NewSandboxTemplateNotFoundError(namespace, name, kind string) *SandboxTemplateNotFoundError {
    return &SandboxTemplateNotFoundError{Namespace: namespace, Name: name, Kind: kind}
}

func (e *SandboxTemplateNotFoundError) Error() string {
    return fmt.Sprintf("sandbox template %s/%s of kind %s not found", e.Namespace, e.Name, e.Kind)
}

func (e *SandboxTemplateNotFoundError) StatusError() *errors.StatusError {
    resource := "agentruntimes"
    if e.Kind == "CodeInterpreter" {
        resource = "codeinterpreters"
    }
    return errors.NewNotFound(schema.GroupResource{Group: "agentcube.volcano.sh", Resource: resource}, e.Name)
}
```

### Logic Flow
1. Read session ID from `x-agentcube-session-id` header
2. If empty, call workload manager to create sandbox
3. If non-empty, load from store
4. Return appropriate errors for not found
5. Require WORKLOAD_MANAGER_URL at construction
6. Load K8s service account token if available

